mapper.select:
/* ====== cmn.menuaccesssrch.selectList =========*/
SELECT A.MENU_ID ,A.USR_ID ,B.USR_NM ,B.ORGN_ID ,FN_GET_ORGNM(B.ORGN_ID) AS ORGN_NM ,TO_CHAR(TO_DATE(A.CONN_DT, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') CONN_DT ,A.IP_INFO ,A.MENU_NM ,A.DUTY_NM FROM CMN_MENU_CONN_LOG_MST A, CMN_USR_MST B WHERE A.USR_ID = B.USR_ID
AND B.ORGN_ID = #{orgnId}
AND B.USR_NM like '%' || #{searchUsrNm} || '%'
AND A.MENU_ID = #{searchMenuList}
AND A.CONN_DT >= #{searchStrtDt}
AND A.CONN_DT < #{searchEndDt} + 1 || '000000000'
order by A.CONN_DT desc
